/**
 * PATCH /users/:id/email
 * Updates a user's email address.
 *
 * @param {object} userRepository - Injected repository with findById, findByEmail, updateEmail
 * @returns Express route handler
 */
function makePatchUserEmailHandler(userRepository) {
  return async function patchUserEmail(req, res) {
    const { id } = req.params;
    const { email } = req.body;

    // AC3: Validate email format
    if (!isValidEmail(email)) {
      return res.status(400).json({ error: 'INVALID_EMAIL_FORMAT' });
    }

    // AC4: Verify user exists
    const user = await userRepository.findById(id);
    if (!user) {
      return res.status(404).json({ error: 'USER_NOT_FOUND' });
    }

    // AC5: Idempotent — same email, no change needed
    if (user.email === email) {
      return res.status(200).json(user);
    }

    // AC2: Check email is not already in use by another user
    const existing = await userRepository.findByEmail(email);
    if (existing) {
      return res.status(409).json({ error: 'EMAIL_ALREADY_IN_USE' });
    }

    // AC1: Perform the update and return the updated user
    const updatedUser = await userRepository.updateEmail(id, email);
    return res.status(200).json(updatedUser);
  };
}

/**
 * Returns true if the given string is a valid RFC-5322-ish email address.
 * Keeps validation intentionally simple: local@domain.tld shape.
 */
function isValidEmail(email) {
  if (typeof email !== 'string') return false;
  // Must contain exactly one @, non-empty local part, domain with at least one dot
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return EMAIL_RE.test(email);
}

module.exports = { makePatchUserEmailHandler, isValidEmail };

